mapper.select:
SELECT ANALYZE_LEVEL AS analyzeLevel, COUNT(*) AS cnt
FROM TB_ANALYZE_RESULT
WHERE SERVER_ID = #{serverId}
  AND ANALYZE_LEVEL IN ('정상', '경고', '에러')
  AND ANALYZE_DATETIME > #{from}
  AND ANALYZE_DATETIME <= #{to}
GROUP BY ANALYZE_LEVEL

mapper.update:
UPDATE TB_ANALYZE_RESULT
SET NOTIFY_YN  = 'Y',
    NOTIFY_AT  = #{notifyAt},
    UPDATED_AT = #{notifyAt}
WHERE SERVER_ID = #{serverId}
  AND ANALYZE_LEVEL IN ('정상', '경고', '에러')
  AND ANALYZE_DATETIME > #{from}
  AND ANALYZE_DATETIME <= #{to}
